import LoginPage from '../support/pages/loginPage.js';

describe('Login Feature', () => {
    let loginPage;

    beforeEach(() => {
        loginPage = new LoginPage();
    });

    // ══════════════════════════════════════════════════════════════════════════
    // @smoke — Critical path tests
    // ══════════════════════════════════════════════════════════════════════════

    it('TC-21: Verify that login works with valid credentials @smoke @regression', () => {
        cy.step('Open login page', () => {
            loginPage.navigate();
        });

        cy.step('Verify login page displays', () => {
            loginPage.verifyLoginPageLoaded();
        });

        cy.step('Enter valid username', () => {
            cy.fixture('credentials.csv').then((csv) => {
                const rows = loginPage.parseCSV(csv);
                const validUser = rows.find(r => r.RoleName === 'Admin');
                loginPage.fillUsername(validUser.Username);
            });
        });

        cy.step('Enter valid password', () => {
            cy.fixture('credentials.csv').then((csv) => {
                const rows = loginPage.parseCSV(csv);
                const validUser = rows.find(r => r.RoleName === 'Admin');
                loginPage.fillPassword(validUser.Password);
            });
        });

        cy.step('Click login button', () => {
            loginPage.clickLogin();
        });

        cy.step('Verify user logged in successfully', () => {
            loginPage.verifyLoginSuccess();
        });
    });

    it('TC-560: Verify that login works with valid credentials (API) @smoke @regression', () => {
        cy.step('Send POST request to /login endpoint', () => {
            cy.fixture('credentials.csv').then((csv) => {
                const rows = loginPage.parseCSV(csv);
                const validUser = rows.find(r => r.RoleName === 'Admin');
                loginPage.loginViaAPI(validUser.Username, validUser.Password).as('loginResponse');
            });
        });

        cy.step('Validate response returns 200 status code', () => {
            cy.get('@loginResponse').then((response) => {
                loginPage.verifyResponseStatus(response, 200);
            });
        });

        cy.step('Validate response contains authentication token', () => {
            cy.get('@loginResponse').then((response) => {
                loginPage.verifyResponseContainsToken(response);
            });
        });
    });

    // ══════════════════════════════════════════════════════════════════════════
    // @regression — Negative tests
    // ══════════════════════════════════════════════════════════════════════════

    it('TC-22: To Test Login Form with Invalid Data @regression', () => {
        cy.step('Navigate to login page', () => {
            loginPage.navigate();
        });

        cy.step('Verify login page displays', () => {
            loginPage.verifyLoginPageLoaded();
        });

        cy.step('Enter username and password', () => {
            loginPage.fillUsername('invaliduser');
            loginPage.fillPassword('invalidpass');
        });

        cy.step('Click login button', () => {
            loginPage.clickLogin();
        });

        cy.step('Verify system accepts the username and password', () => {
            // System accepts input but should show error after validation
            loginPage.verifyInvalidCredentialsError();
        });
    });

    it('TC-562: Verify that login fails with invalid password @regression', () => {
        cy.step('Send POST request to /login endpoint with valid username and invalid password', () => {
            cy.fixture('credentials.csv').then((csv) => {
                const rows = loginPage.parseCSV(csv);
                const validUser = rows.find(r => r.RoleName === 'Admin');
                loginPage.loginViaAPI(validUser.Username, 'WrongPassword123').as('loginResponse');
            });
        });

        cy.step('Validate response returns 401 status code', () => {
            cy.get('@loginResponse').then((response) => {
                loginPage.verifyResponseStatus(response, 401);
            });
        });

        cy.step('Validate error message indicates invalid credentials', () => {
            cy.get('@loginResponse').then((response) => {
                loginPage.verifyResponseErrorMessage(response, 'invalid credentials');
            });
        });
    });

    it('TC-561: Verify that login fails with invalid username @regression', () => {
        cy.step('Send POST request to /login endpoint with invalid username and valid password', () => {
            cy.fixture('credentials.csv').then((csv) => {
                const rows = loginPage.parseCSV(csv);
                const validUser = rows.find(r => r.RoleName === 'Admin');
                loginPage.loginViaAPI('InvalidUser999', validUser.Password).as('loginResponse');
            });
        });

        cy.step('Validate response returns 401 status code', () => {
            cy.get('@loginResponse').then((response) => {
                loginPage.verifyResponseStatus(response, 401);
            });
        });

        cy.step('Validate error message indicates invalid credentials', () => {
            cy.get('@loginResponse').then((response) => {
                loginPage.verifyResponseErrorMessage(response, 'invalid credentials');
            });
        });
    });

    it('TC-563: Verify that login fails with empty username @regression', () => {
        cy.step('Send POST request to /login endpoint with empty username', () => {
            cy.fixture('credentials.csv').then((csv) => {
                const rows = loginPage.parseCSV(csv);
                const validUser = rows.find(r => r.RoleName === 'Admin');
                loginPage.loginViaAPI('', validUser.Password).as('loginResponse');
            });
        });

        cy.step('Validate response returns 400 status code', () => {
            cy.get('@loginResponse').then((response) => {
                loginPage.verifyResponseStatus(response, 400);
            });
        });

        cy.step('Validate error message indicates missing username', () => {
            cy.get('@loginResponse').then((response) => {
                loginPage.verifyResponseErrorMessage(response, 'missing username');
            });
        });
    });

    it('TC-564: Verify that login fails with empty password @regression', () => {
        cy.step('Send POST request to /login endpoint with empty password', () => {
            cy.fixture('credentials.csv').then((csv) => {
                const rows = loginPage.parseCSV(csv);
                const validUser = rows.find(r => r.RoleName === 'Admin');
                loginPage.loginViaAPI(validUser.Username, '').as('loginResponse');
            });
        });

        cy.step('Validate response returns 400 status code', () => {
            cy.get('@loginResponse').then((response) => {
                loginPage.verifyResponseStatus(response, 400);
            });
        });

        cy.step('Validate error message indicates missing password', () => {
            cy.get('@loginResponse').then((response) => {
                loginPage.verifyResponseErrorMessage(response, 'missing password');
            });
        });
    });
});

// Custom cy.step() command for better test reporting
Cypress.Commands.add('step', (message, fn) => {
    cy.log(`**${message}**`);
    return fn();
});

